import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe dinámicamente para evitar detección
      const frame = document.createElement('iframe');

      // Configurar atributos de forma dinámica
      const attrs = {
        'src': src,
        'width': '100%',
        'height': '100%',
        'frameborder': '0',
        'allowfullscreen': 'true',
        'allow': 'autoplay; fullscreen; picture-in-picture',
        'sandbox': 'allow-scripts allow-same-origin allow-presentation',
        'referrerpolicy': 'no-referrer-when-downgrade',
        'loading': 'lazy'
      };

      Object.keys(attrs).forEach(key => {
        frame.setAttribute(key, attrs[key]);
      });

      // Estilos para evitar detección
      frame.style.cssText = `
        border: none;
        outline: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
      `;

      // Limpiar contenedor y agregar iframe
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      // Manejar errores
      frame.onerror = () => {
        if (onError) onError();
      };

      return () => {
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg"
      style={{ minHeight: '400px' }}
    />
  );
};

export default VideoFrame;
